import './NavigationRail.scss';

import { Divider } from ':components/Divider';
import { Icon } from ':components/Icon';
import { classNames } from ':helpers/classnames';
import React from 'react';

import type { NavigationRailProps } from './NavigationRail.types';

const NavigationRailIcon = ({ iconName, onClick, selected, disabled }) => (
	<div
		onClick={disabled ? () => null : onClick}
		className={classNames(
			'dsb_navigationRail__icon',
			selected && 'dsb_navigationRail__icon-selected',
			disabled && 'dsb_navigationRail__icon-disabled',
		)}
		tabIndex={0}
	>
		<Icon iconName={iconName} size={'large'} />
	</div>
);

export const NavigationRail: React.FC<NavigationRailProps> = ({ value, className, dataTestId = 'NavigationRail' }) => (
	<div data-testid={dataTestId} className={classNames('dsb_navigationRail', className)}>
		{value.map(icon => {
			if (icon?.divider) {
				return <Divider />;
			}
			return (
				<NavigationRailIcon
					disabled={icon.disabled}
					selected={icon.selected}
					iconName={icon.iconName}
					onClick={icon.onClick}
				/>
			);
		})}
	</div>
);
